const cvPdf = 'data:application/pdf;base64,';
const heroPhoto = 'data:image/jpeg;base64,';
const orbitMain = 'data:image/jpeg;base64,';
const ot0Image = 'data:image/jpeg;base64,';
const ot1Image = 'data:image/jpeg;base64,';
const ot2Image = 'data:image/jpeg;base64,';
const ot3Image = 'data:image/jpeg;base64,';

function applyBase64Assets() {
  document.getElementById('downloadCv').href = cvPdf;
  document.getElementById('heroPhoto').src = heroPhoto;
  document.getElementById('orbitMain').src = orbitMain;
  document.getElementById('ot0Img').src = ot0Image;
  document.getElementById('ot1Img').src = ot1Image;
  document.getElementById('ot2Img').src = ot2Image;
  document.getElementById('ot3Img').src = ot3Image;
}
if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", applyBase64Assets);
} else {
  applyBase64Assets();
}